// Merge webhook and manual trigger data into consistent format
let items = [];

try {
  // From webhook trigger (single contact)
  const webhookData = $('Webhook Trigger').first().json;
  if (webhookData && webhookData.body) {
    items.push({
      json: {
        notion_page_id: webhookData.body.notion_page_id,
        full_name: webhookData.body.full_name,
        linkedin_url: webhookData.body.linkedin_url,
        company: webhookData.body.company || '',
        title: webhookData.body.title || ''
      }
    });
  }
} catch(e) {}

try {
  // From manual trigger (batch from Notion query)
  const notionResults = $('Get Unresearched Contacts').first().json.results || [];
  for (const page of notionResults) {
    const props = page.properties;
    const name = props['Name']?.title?.[0]?.text?.content || '';
    const linkedinUrl = props['LinkedIn Profile']?.url || '';
    const company = props['Company']?.rich_text?.[0]?.text?.content || '';
    const title = props['Title']?.rich_text?.[0]?.text?.content || '';
    items.push({
      json: {
        notion_page_id: page.id,
        full_name: name,
        linkedin_url: linkedinUrl,
        company: company,
        title: title
      }
    });
  }
} catch(e) {}

return items;

// Score lead from Apify LinkedIn data
// Scoring: employee count (0-5) + title (0-3) = max 8 pts
const lead = $('Loop Over Contacts').first().json;

// Apify data
let apifyData = {};
try {
  const raw = $('Apify LinkedIn Scraper').first().json;
  apifyData = {
    headline: raw.headline || '',
    fullName: raw.fullName || lead.full_name,
    companyName: raw.experiences?.[0]?.companyName || lead.company,
    companyTitle: raw.experiences?.[0]?.title || lead.title,
    jobDescription: raw.experiences?.[0]?.jobDescription || '',
    profilePicture: raw.profilePicture || '',
    location: raw.location || ''
  };
} catch(e) {
  apifyData = { headline: '', fullName: lead.full_name, companyName: lead.company, companyTitle: lead.title };
}

// Parse employee count from Apify
let employeeCount = 0;
try {
  const raw = $('Apify LinkedIn Scraper').first().json;
  const empSources = [
    raw.experiences?.[0]?.companyEmployees,
    raw.experiences?.[0]?.companySize,
    raw.experiences?.[0]?.companyStaffCountRange,
    raw.experiences?.[0]?.companyEmployeeCount,
    raw.companySize,
    raw.employeesCount
  ];
  for (const empRaw of empSources) {
    if (empRaw == null) continue;
    if (typeof empRaw === 'number' && empRaw > 0) { employeeCount = empRaw; break; }
    if (typeof empRaw === 'string') {
      const rangeMatch = empRaw.match(/(\\d[\\d,]*)\\s*[-\u2013]\\s*(\\d[\\d,]*)/);
      if (rangeMatch) {
        employeeCount = Math.round((parseInt(rangeMatch[1].replace(/,/g, '')) + parseInt(rangeMatch[2].replace(/,/g, ''))) / 2);
        break;
      }
      const numMatch = empRaw.match(/(\\d[\\d,]*)/);
      if (numMatch) { employeeCount = parseInt(numMatch[1].replace(/,/g, '')); break; }
    }
  }
} catch(e) {}

// ============ SCORING (max 8 pts) ============
let score = 0;
let breakdown = [];

// 1. Employee Count (0-5)
if (employeeCount >= 50 && employeeCount <= 200) { score += 5; breakdown.push('Emp 50-200: +5'); }
else if (employeeCount >= 20 && employeeCount < 50) { score += 4; breakdown.push('Emp 20-49: +4'); }
else if (employeeCount >= 10 && employeeCount < 20) { score += 3; breakdown.push('Emp 10-19: +3'); }
else if (employeeCount > 200) { score += 3; breakdown.push('Emp 200+: +3'); }
else if (employeeCount > 0) { score += 1; breakdown.push('Emp <10: +1'); }
else { breakdown.push('Emp unknown: +0'); }

// 2. Title (0-3)
const t = (apifyData.companyTitle || '').toLowerCase();
if (/\\b(ceo|founder|co-founder|owner)\\b/.test(t)) { score += 3; breakdown.push('CEO/Founder/Owner: +3'); }
else if (/\\b(coo|president|vp|vice president|chief)\\b/.test(t)) { score += 2; breakdown.push('COO/President/VP: +2'); }
else if (/\\b(director|head of)\\b/.test(t)) { score += 1; breakdown.push('Director/Head: +1'); }
else if (t) { breakdown.push('Other title: +0'); }
else { breakdown.push('Title unknown: +0'); }

// Tier
let tier = score >= 7 ? 'Tier 1' : score >= 5 ? 'Tier 2' : score >= 3 ? 'Tier 3' : 'Tier 4';

return [{
  json: {
    notion_page_id: lead.notion_page_id,
    full_name: apifyData.fullName || lead.full_name,
    linkedin_url: lead.linkedin_url,
    headline: apifyData.headline,
    company_name: apifyData.companyName,
    person_title: apifyData.companyTitle,
    job_description: apifyData.jobDescription,
    employee_count: employeeCount,
    priority_score: score,
    max_score: 8,
    tier: tier,
    score_breakdown: breakdown.join(' | ')
  }
}];

